// PHASE 7: Community & Public Health (100 Questions)
const phase7 = {
  phase: 7, title: "Community & Public Health", icon: "🌍", color: "#16a085",
  questions: [
    { id:"p7q1", question:"Primary prevention in public health focuses on:", options:["Early detection of disease","Treating existing conditions","Preventing disease BEFORE it occurs (e.g., vaccination, health education, lifestyle modification)","Rehabilitation"], answer:2, explanation:"Primary prevention prevents disease occurrence: immunizations, health promotion, risk factor reduction (stop smoking, healthy diet), safety measures. Secondary: early detection. Tertiary: reduce disability." },
    { id:"p7q2", question:"Herd immunity occurs when:", options:["All members of a population are vaccinated","A sufficient proportion of the population is immune (vaccinated/recovered) to prevent disease spread to unvaccinated individuals","Only children are vaccinated","Natural immunity is achieved by all"], answer:1, explanation:"Herd immunity threshold varies by disease (measles ~95%, polio ~80–85%). When enough people are immune, transmission chains break, protecting vulnerable individuals who cannot be vaccinated." },
    { id:"p7q3", question:"The epidemiological triad consists of:", options:["Host, Agent, Vector","Host, Agent, Environment","Pathogen, Patient, Prevention","Cause, Effect, Treatment"], answer:1, explanation:"Epidemiological triad: Host (susceptible person), Agent (cause — biological, chemical, physical), Environment (factors enabling interaction). Disease occurs when all three interact favorably." },
    { id:"p7q4", question:"Incidence rate measures:", options:["Total cases in a population at a point in time","NEW cases of disease occurring in a defined population over a defined time period","Mortality rate","Recovery rate"], answer:1, explanation:"Incidence: new cases/population at risk × 1000 (or 100,000) per time period. Measures disease RISK. Prevalence: all existing cases (new + old) at a point in time. Measures disease BURDEN." },
    { id:"p7q5", question:"Prevalence rate measures:", options:["New cases only","Rate of death from a disease","All existing cases (new + old) in a population at a given time","Rate of hospitalization"], answer:2, explanation:"Prevalence = existing cases / total population × 1000. Includes both new (incident) and existing cases. High prevalence can result from high incidence OR long disease duration. Used for resource planning." },
    { id:"p7q6", question:"An outbreak is defined as:", options:["Any case of an infectious disease","Occurrence of more cases of a disease than expected in a defined area/time — even 2 cases of a rare disease","Only national epidemics","10 or more cases of any disease"], answer:1, explanation:"Outbreak: more cases than expected (above baseline) in a specific area/time. 2 linked cases of a rare disease (e.g., Ebola) = outbreak. Epidemic: widespread. Pandemic: global epidemic." },
    { id:"p7q7", question:"Which disease has been officially eradicated worldwide?", options:["Polio","Measles","Smallpox (variola)","Malaria"], answer:2, explanation:"Smallpox is the only human disease officially eradicated (declared by WHO in 1980), through global vaccination campaigns. Polio is close to eradication. Guinea worm is near eradication." },
    { id:"p7q8", question:"Sensitivity of a screening test refers to:", options:["Ability to correctly identify those WITHOUT disease (true negative rate)","Ability to correctly identify those WITH disease (true positive rate)","Cost of the test","Specificity vs. sensitivity tradeoff"], answer:1, explanation:"Sensitivity = TP/(TP+FN). High sensitivity → few false negatives → best for screening (don't miss disease). Specificity = TN/(TN+FP). High specificity → few false positives → best for diagnosis confirmation." },
    { id:"p7q9", question:"The Expanded Programme on Immunization (EPI) of the WHO includes which vaccines as a minimum:", options:["Only MMR","BCG, OPV/IPV, DTP, HepB, Hib, measles, rubella","Only polio and DTP","Only hepatitis B and influenza"], answer:1, explanation:"WHO EPI core vaccines: BCG (TB), OPV/IPV (polio), DTP (diphtheria, tetanus, pertussis), hepatitis B, Hib, measles, rubella, and rotavirus/pneumococcal in many programs." },
    { id:"p7q10", question:"Which communicable disease is a notifiable (reportable) condition in most countries?", options:["Common cold","Influenza (seasonal)","Tuberculosis, cholera, typhoid, HIV — all notifiable diseases","Mild gastroenteritis"], answer:2, explanation:"Notifiable diseases are required by law to be reported to public health authorities: TB, cholera, typhoid, meningococcal disease, measles, HIV/AIDS, hepatitis B/C, foodborne illness outbreaks. Allows surveillance and outbreak control." },
    { id:"p7q11", question:"Body Mass Index (BMI) is calculated as:", options:["Weight (kg) / Height (cm)","Weight (kg) / Height (m²)","Height (m) / Weight (kg)","Weight (lb) / Height (in)²"], answer:1, explanation:"BMI = weight(kg) / height(m²). Classification: <18.5 underweight, 18.5–24.9 normal, 25–29.9 overweight, ≥30 obese, ≥40 morbidly obese. Widely used but doesn't account for muscle mass or fat distribution." },
    { id:"p7q12", question:"The route of transmission for TB (tuberculosis) is:", options:["Contact with infected skin","Fecal-oral route","Airborne (droplet nuclei <5μm that remain suspended in air)","Vector-borne (mosquitoes)"], answer:2, explanation:"TB: airborne transmission via droplet nuclei (<5 μm) that remain airborne for hours. One infectious case can infect 10–15 contacts/year. Requires airborne precautions, N95 respirator, negative-pressure room." },
    { id:"p7q13", question:"Which is the most effective method to prevent transmission of COVID-19 and respiratory infections?", options:["Prophylactic antibiotics","Vaccination, hand hygiene, mask-wearing, ventilation, and distancing (bundles)","Vitamin C supplementation","Antivirals prophylactically"], answer:1, explanation:"Respiratory infection prevention bundle: vaccination (primary prevention), hand hygiene, mask-wearing (surgical/N95 for high-risk), physical distancing, ventilation improvement. No single measure is fully protective." },
    { id:"p7q14", question:"Cholera is transmitted via:", options:["Airborne droplets","Person-to-person contact","Contaminated water and food (fecal-oral route)","Mosquito bites"], answer:2, explanation:"Cholera (Vibrio cholerae): fecal-oral transmission through contaminated water (typically during floods, poor sanitation). 'Rice water' stools. Prevention: clean water, sanitation, hygiene. Oral cholera vaccine available." },
    { id:"p7q15", question:"The Cold Chain in immunization programs refers to:", options:["Administering vaccines in cold climates only","System of refrigerated storage and transport keeping vaccines at 2–8°C from manufacture to patient","Freezing all vaccines","Transport of blood products"], answer:1, explanation:"Cold chain: vaccines require continuous temperature maintenance (2–8°C for most; some require freezing) from manufacturer to the point of administration. Breaks in cold chain destroy vaccine potency." },
    { id:"p7q16", question:"Maternal mortality ratio (MMR) is defined as:", options:["Number of maternal deaths per 1,000 live births","Number of maternal deaths per 100,000 live births from causes related to pregnancy/childbirth","Deaths in women of reproductive age per total deaths","Infant deaths per 1,000 live births"], answer:1, explanation:"MMR = maternal deaths (during pregnancy or within 42 days of delivery from pregnancy-related causes) per 100,000 live births. SDG target: <70 per 100,000 by 2030." },
    { id:"p7q17", question:"Which microorganism causes malaria?", options:["Bacteria","Virus","Plasmodium species (protozoan parasite) — transmitted by Anopheles mosquito","Helminth (worm)"], answer:2, explanation:"Malaria: caused by Plasmodium (P. falciparum — most severe, P. vivax, P. ovale, P. malariae), transmitted by female Anopheles mosquito. Prevention: insecticide-treated bed nets, indoor residual spraying, chemoprophylaxis." },
    { id:"p7q18", question:"The disability-adjusted life year (DALY) measures:", options:["Only years of life lost to death","Combined burden of disease: Years of Life Lost (YLL) to premature death + Years Lived with Disability (YLD)","Only disability, not mortality","Quality of life score"], answer:1, explanation:"DALY = YLL + YLD. One DALY = one year of healthy life lost. Used to compare disease burden across conditions and countries. DALYs enable health priority setting and resource allocation." },
    { id:"p7q19", question:"The Ottawa Charter for Health Promotion (1986) identifies which prerequisites for health?", options:["Only medicine and nutrition","Peace, shelter, education, food, income, stable ecosystem, social justice, equity","Vaccination and clean water only","Economic development only"], answer:1, explanation:"Ottawa Charter prerequisites: peace, shelter, education, food, income, a stable ecosystem, sustainable resources, social justice, and equity. Health promotion = enabling people to increase control over and improve their health." },
    { id:"p7q20", question:"Contact tracing is performed to:", options:["Track patients' hospital records","Identify, assess, and manage people exposed to a disease to interrupt transmission chains","Count cases for statistics only","Determine vaccine efficacy"], answer:1, explanation:"Contact tracing: systematic identification of all persons who had contact with an infectious case during their infectious period, notifying them, testing, quarantining if exposed, and treating if infected. Essential for STIs, TB, COVID-19, Ebola." },
    { id:"p7q21", question:"The Millennium Development Goals (MDGs) were replaced by the Sustainable Development Goals (SDGs) in:", options:["2000","2010","2015","2020"], answer:2, explanation:"MDGs (2000–2015) replaced by 17 SDGs in 2015 (Agenda 2030). SDG 3: Good Health and Well-being. SDG 6: Clean water and sanitation. SDGs are broader, more integrated, and include all countries." },
    { id:"p7q22", question:"Which food preservation method DOES NOT prevent Clostridium botulinum growth?", options:["High-temperature autoclaving","Acidification (pH <4.5)","Low-temperature refrigeration (4°C)","Home canning at 100°C"], answer:3, explanation:"C. botulinum spores resist boiling (100°C). Only pressure cooking (autoclaving at 121°C for 15 min) destroys spores. Home canning at 100°C is INADEQUATE for low-acid foods → botulism risk." },
    { id:"p7q23", question:"What is the recommended daily water intake for adults in normal conditions?", options:["500 mL–1 L","1–2 L","2–3 L (about 8 cups, though needs vary)","5 L"], answer:2, explanation:"General recommendation: ~2–3 L/day (including water from food). Needs increase with heat, exercise, illness, pregnancy/lactation. Exact requirement varies. WHO minimum safe water access: 20 L/person/day." },
    { id:"p7q24", question:"Infant mortality rate (IMR) is calculated as:", options:["Deaths of children under 5 years per 1,000 live births","Deaths of infants under 1 year of age per 1,000 live births","Deaths of infants in hospital per total births","Neonatal deaths per 100,000 population"], answer:1, explanation:"IMR = infant deaths (under 1 year) / live births × 1,000. IMR reflects overall health system quality, socioeconomic development, and maternal-child health services. SDG target: <12/1,000 by 2030." },
    { id:"p7q25", question:"Which of the following is an example of secondary prevention?", options:["Childhood vaccination","Cancer screening (mammography, Pap smear, colonoscopy)","Cardiac rehabilitation","Health education in schools"], answer:1, explanation:"Secondary prevention: early detection to halt/slow progression (screening + early treatment). Mammography (breast cancer), Pap smear (cervical cancer), PSA (prostate), colonoscopy (colon cancer), BP screening (hypertension)." },
    { id:"p7q26", question:"Social determinants of health include:", options:["Only genetics","Income, education, employment, housing, social support, neighborhood safety, food security","Biological factors only","Healthcare access alone"], answer:1, explanation:"Social determinants: non-medical factors that influence health — socioeconomic status, education, employment, housing, neighborhood, food access, social support, racism/discrimination. Explain ~30–55% of health outcomes." },
    { id:"p7q27", question:"Which route transmits dengue fever?", options:["Fecal-oral","Airborne","Aedes aegypti mosquito bite","Direct contact with infected person"], answer:2, explanation:"Dengue: arboviruse transmitted by Aedes aegypti (and A. albopictus) mosquitoes. Day-biting mosquito. No human-to-human transmission. Prevention: eliminating standing water (breeding sites), bed nets, repellents." },
    { id:"p7q28", question:"The purpose of quarantine in public health is:", options:["Treating infected individuals","Separating and restricting movement of people exposed to infectious disease who may be incubating it","Punishing people with disease","Universal testing of the population"], answer:1, explanation:"Quarantine: separates people who MAY be infectious (exposed, incubating) from those who aren't. Isolation: separates people who ARE infectious. Quarantine duration = incubation period of specific disease." },
    { id:"p7q29", question:"Which health model describes behavior change as occurring in stages?", options:["Biomedical model","Transtheoretical model (Stages of Change): Precontemplation, Contemplation, Preparation, Action, Maintenance","Health Belief Model","Social Learning Theory only"], answer:1, explanation:"Transtheoretical model: Precontemplation (no intention), Contemplation (considering change within 6 months), Preparation (ready, planning), Action (changed <6 months), Maintenance (>6 months). Relapse is common and expected." },
    { id:"p7q30", question:"Universal precautions (standard precautions) apply to:", options:["Only patients with known HIV","Only patients with hepatitis B","ALL patients — treat all blood/body fluids as potentially infectious","Only patients in isolation"], answer:2, explanation:"Standard precautions: treat ALL blood, body fluids, secretions, excretions (except sweat), non-intact skin, and mucous membranes as potentially infectious — regardless of known diagnosis." },
    { id:"p7q31", question:"Which is the MOST common foodborne pathogen globally?", options:["Listeria monocytogenes","Clostridium botulinum","Campylobacter, Salmonella, E. coli O157:H7, and Norovirus (top global causes)","Shigella only"], answer:2, explanation:"Top global foodborne pathogens by illness: Norovirus (most common cause globally), Salmonella, Campylobacter, E. coli. By mortality: Salmonella typhi, Listeria (in vulnerable populations), E. coli O157:H7." },
    { id:"p7q32", question:"Ebola virus disease is transmitted by:", options:["Airborne droplets","Mosquito bites","Direct contact with blood, body fluids, or organs of infected humans or animals","Contaminated water"], answer:2, explanation:"Ebola: direct contact with blood/body fluids of sick/deceased persons. NOT airborne. Healthcare workers at highest risk without PPE. Requires contact + droplet precautions (some guidelines add airborne). High mortality (25–90%)." },
    { id:"p7q33", question:"Which country has the highest malaria burden?", options:["India","Nigeria (plus DRC, Uganda, Mozambique — sub-Saharan Africa accounts for ~95% of cases)","Brazil","Indonesia"], answer:1, explanation:"Sub-Saharan Africa accounts for ~95% of global malaria cases and deaths. Nigeria and DRC together account for ~35% of global malaria cases. P. falciparum is the dominant and most deadly species in Africa." },
    { id:"p7q34", question:"Point-of-care testing (POCT) in community health:", options:["Requires laboratory infrastructure","Provides near-patient diagnostic testing at or near the site of care — rapid HIV, malaria, pregnancy tests","Only available in hospitals","Is less accurate than lab testing always"], answer:1, explanation:"POCT: diagnostic tests performed at or near patient (clinic, home, field). Examples: rapid HIV, malaria RDTs, blood glucose, urine pregnancy. Enables immediate clinical decisions in resource-limited settings." },
    { id:"p7q35", question:"The most effective method of sterilization (killing ALL microorganisms including spores) is:", options:["Boiling at 100°C","Pasteurization","Steam autoclave at 121°C for 15 minutes under pressure","70% isopropyl alcohol"], answer:2, explanation:"Autoclave (steam sterilization): 121°C at 15 psi for 15–30 minutes kills ALL microorganisms including highly resistant spores. Gold standard for sterilization of surgical instruments and heat-stable items." },
    { id:"p7q36", question:"A public health nurse is conducting a community needs assessment. The FIRST step is:", options:["Implement a health program","Define the community and collect demographic/health data (epidemiological data, existing resources, community views)","Evaluate the program","Train community health workers"], answer:1, explanation:"Community needs assessment steps: 1) Define community, 2) Collect data (epidemiological, qualitative, existing resources), 3) Analyze data, 4) Identify priorities, 5) Plan interventions, 6) Implement, 7) Evaluate." },
    { id:"p7q37", question:"Which immunization prevents cervical cancer?", options:["BCG","Hepatitis B","Human papillomavirus (HPV) vaccine — protects against HPV types 16 and 18 (cause ~70% of cervical cancers)","Meningococcal vaccine"], answer:2, explanation:"HPV vaccine (Gardasil 9, Cervarix): given to girls (and boys) at 9–14 years before sexual activity. Prevents infection with HPV types 16/18 (cervical cancer), 6/11 (genital warts). 2 doses if <15 years; 3 doses if ≥15." },
    { id:"p7q38", question:"Directly Observed Therapy Short Course (DOTS) is a strategy for:", options:["Malaria treatment","Tuberculosis treatment — ensures patient takes every dose under observation to prevent drug resistance","HIV treatment","Leprosy treatment"], answer:1, explanation:"DOTS: patient takes TB medication in front of a healthcare worker or trained observer for entire 6-month course. Prevents treatment interruption, drug resistance (MDR-TB), and treatment failure. WHO recommended strategy." },
    { id:"p7q39", question:"The best indicator of a nation's health status is:", options:["GDP per capita","Number of hospitals","Infant mortality rate (IMR) and maternal mortality ratio (MMR)","Number of physicians"], answer:2, explanation:"IMR and MMR are composite indicators of a country's overall health status, reflecting nutrition, clean water, health services quality, socioeconomic conditions, and equity. Lower = better health system." },
    { id:"p7q40", question:"Personal protective equipment (PPE) for standard precautions includes:", options:["Only gloves","Gloves, gown, mask (when splash risk), eye protection (when splash risk) — donned based on anticipated exposure","Full PPE for all contacts","Only mask and gown"], answer:1, explanation:"Standard precautions PPE: gloves (contact with blood/fluids/mucous membranes), gown (clothing protection), mask + eye protection/face shield (splash/spray risk). Additional precautions for specific transmission routes." },
    { id:"p7q41", question:"Sanitation refers to:", options:["Vaccination programs","Provision of facilities and services for safe disposal of human waste and maintenance of hygienic conditions","Food safety only","Water treatment only"], answer:1, explanation:"Sanitation: safe management of human feces/urine (toilets/latrines, sewage treatment, handwashing facilities). Poor sanitation causes diarrhea, cholera, typhoid, helminth infections — affects 3.6 billion people globally." },
    { id:"p7q42", question:"Which concept describes the proportion of exposed people who develop disease?", options:["Prevalence rate","Attributable risk","Attack rate (in outbreak investigations) — cases / exposed × 100%","Relative risk"], answer:2, explanation:"Attack rate: proportion of exposed population that develops disease during an outbreak = cases/exposed × 100. Used in food poisoning investigations to identify the source food (highest attack rate)." },
    { id:"p7q43", question:"Health promotion differs from disease prevention in that:", options:["They are identical","Health promotion focuses on positive enhancement of well-being and capacity; disease prevention focuses on avoiding specific diseases","Health promotion only covers vaccination","Disease prevention covers all health interventions"], answer:1, explanation:"Health promotion (Ottawa Charter): enables people to increase control over health — positive, empowering, addresses determinants. Disease prevention: specific protective measures against specific diseases (vaccination, screening, chemoprophylaxis)." },
    { id:"p7q44", question:"The APGAR score for a community health needs assessment (not neonatal) assesses:", options:["Only maternal health","Adaptation, Partnership, Growth, Affection, Resolve — used in family assessment","Individual vital signs","Mental health only"], answer:1, explanation:"APGAR family assessment (Smilkstein): Adaptation (crisis resources), Partnership (communication), Growth (personal development), Affection (emotional intimacy), Resolve (commitment to family). Measures family function." },
    { id:"p7q45", question:"Non-communicable diseases (NCDs) are responsible for what proportion of global mortality?", options:["25%","41% (approximately) — 74% of all deaths globally by 2020 WHO data","60%","90%"], answer:1, explanation:"WHO 2020 data: NCDs cause ~74% of all deaths globally. Four main NCDs: cardiovascular disease (most common), cancer, chronic respiratory disease, diabetes. Behavioral risk factors: tobacco, unhealthy diet, physical inactivity, harmful alcohol use." },
    { id:"p7q46", question:"Which water treatment method is most effective in field/emergency settings?", options:["Settling only","Chlorination + filtration (turbidity removal first, then disinfection)","Boiling alone (effective if fuel available)","UV light only"], answer:2, explanation:"Emergency water treatment: remove turbidity (sedimentation/filtration — improves chlorination efficacy), then chlorinate (0.5 mg/L free residual chlorine after 30 min contact). Boiling is effective but requires fuel. Combination is best." },
    { id:"p7q47", question:"Relative Risk (RR) of 1.0 means:", options:["Doubled risk in exposed group","Exposure is protective","No association between exposure and disease — same risk in exposed and unexposed","Exposure causes all cases"], answer:2, explanation:"RR = risk in exposed / risk in unexposed. RR=1: no association; RR>1: exposure increases risk; RR<1: exposure is protective. RR=2: exposed have double the risk. Used in cohort studies." },
    { id:"p7q48", question:"The reproductive number (R0) of a disease represents:", options:["Number of deaths per case","Average number of secondary cases generated by one infectious case in a fully susceptible population","Case fatality rate","Duration of infectivity"], answer:1, explanation:"R0 (basic reproduction number): if R0>1, epidemic grows; R0<1, epidemic dies out; R0=1, endemic equilibrium. Measles R0=12–18 (highly transmissible); COVID-19 original strain ~2–3; Ebola ~2." },
    { id:"p7q49", question:"Which occupational hazard classification includes noise, heat, and radiation?", options:["Chemical hazards","Biological hazards","Physical hazards","Ergonomic hazards"], answer:2, explanation:"Occupational hazard categories: Physical (noise, vibration, extreme temperatures, radiation), Chemical (solvents, dusts, gases), Biological (bloodborne, airborne pathogens), Ergonomic (repetitive strain, improper posture), Psychosocial (stress, burnout)." },
    { id:"p7q50", question:"The International Health Regulations (IHR) require countries to report:", options:["All infectious diseases","Only 4 events always reportable to WHO: smallpox, polio (wild type), SARS, and human influenza caused by new subtype — plus any unusual health event that may be a PHEIC","Only new diseases","Any disease with >100 deaths"], answer:1, explanation:"IHR (2005): requires notification to WHO of any event that may constitute a Public Health Emergency of International Concern (PHEIC). Always reportable: smallpox, wild poliovirus, SARS, new influenza subtype." },
    { id:"p7q51", question:"Which route is dengue hemorrhagic fever transmitted?", options:["Aedes mosquito (day-biting)","Anopheles mosquito","Direct contact","Fecal-oral"], answer:0, explanation:"Dengue fever (all types including DHF): transmitted by Aedes aegypti (primary vector) and Aedes albopictus. Day-biting mosquito. DHF/DSS typically in secondary dengue infection with a different serotype." },
    { id:"p7q52", question:"'Miasma theory' was replaced by which major advance in public health?", options:["Germ theory of disease (Pasteur, Koch) — microorganisms cause specific diseases","Social determinants of health","Evidence-based medicine","Genomics"], answer:0, explanation:"Miasma theory (disease from bad air/smells) was disproven by germ theory (1860s–1880s). Pasteur: microorganisms cause disease/fermentation. Koch: Koch's postulates established causation. Foundation of modern microbiology and public health." },
    { id:"p7q53", question:"The role of a community health nurse includes:", options:["Only curative care in clinics","Assessment, planning, implementing, and evaluating health programs at the population level — including health education, home visits, epidemiology","Only hospital discharge planning","Only immunization administration"], answer:1, explanation:"Community health nursing: population-focused practice. Roles: health educator, case manager, advocate, epidemiologist, collaborator, researcher, outreach worker. Works in homes, schools, workplaces, clinics, and communities." },
    { id:"p7q54", question:"Which is the most accurate method for diagnosing pulmonary TB?", options:["Chest X-ray alone","Tuberculin skin test (Mantoux)","Sputum culture for Mycobacterium tuberculosis (gold standard — though slow)","Blood culture"], answer:2, explanation:"Sputum culture (on Lowenstein-Jensen or BACTEC) is the gold standard for TB diagnosis (most sensitive/specific) but takes 2–8 weeks. Sputum smear microscopy (AFB): faster but less sensitive. GeneXpert (molecular): rapid, highly sensitive." },
    { id:"p7q55", question:"A community outbreak of diarrhea with high attack rate traced to a common source (buffet meal). This is:", options:["Propagated epidemic","Point source epidemic","Mixed epidemic","Vector-borne outbreak"], answer:1, explanation:"Point source epidemic: all cases exposed to same source at same time. Epidemic curve shows sharp peak within one incubation period. Common vehicle (food, water). Contrast: propagated (person-to-person spread, multiple peaks)." },
    { id:"p7q56", question:"Which UN Sustainable Development Goal is specifically related to health?", options:["SDG 1 (No Poverty)","SDG 3 (Good Health and Well-Being)","SDG 4 (Quality Education)","SDG 13 (Climate Action)"], answer:1, explanation:"SDG 3: Ensure healthy lives and promote well-being for all at all ages. Targets include: maternal mortality, child mortality, HIV/AIDS/TB/malaria, mental health, substance abuse, NCDs, universal health coverage, and health workforce." },
    { id:"p7q57", question:"The Alma Ata Declaration (1978) introduced the concept of:", options:["MDGs","Health for All 2000 through Primary Health Care (PHC) as the key to achieving it","Universal health coverage","Social determinants of health"], answer:1, explanation:"Alma Ata 1978: 'Health for All by the Year 2000' through Primary Health Care (PHC). PHC pillars: equitable distribution, community participation, multisectoral approach, appropriate technology, focus on prevention." },
    { id:"p7q58", question:"Universal Health Coverage (UHC) means:", options:["Free healthcare for all","All people can access quality health services without suffering financial hardship","Unlimited healthcare with no cost","Only emergency care is universal"], answer:1, explanation:"UHC (WHO): all people receive the health services they need (promotive, preventive, curative, rehabilitative, palliative) without financial hardship. Three dimensions: who is covered, what services, proportion of costs covered." },
    { id:"p7q59", question:"Which vaccination is given intradermally (in the skin)?", options:["Hepatitis B (IM)","DTP (IM)","BCG (intradermal — left deltoid)","Polio (oral or IM/SC)"], answer:2, explanation:"BCG (Bacillus Calmette-Guérin) is given intradermally in the upper left arm. Forms a wheal at injection site → papule → pustule → scar. Correct technique critical for efficacy." },
    { id:"p7q60", question:"The Chain of Infection includes:", options:["Cause, Effect, Prevention","Infectious agent, Reservoir, Portal of exit, Mode of transmission, Portal of entry, Susceptible host","Host, Agent, Environment","Exposure, Incubation, Illness, Recovery"], answer:1, explanation:"Chain of infection (6 links): 1)Infectious agent, 2)Reservoir (where it lives), 3)Portal of exit (how it leaves reservoir), 4)Mode of transmission, 5)Portal of entry (into new host), 6)Susceptible host. Breaking any link prevents infection." },
    { id:"p7q61", question:"Hand hygiene with soap and water vs. alcohol-based hand rub — soap is PREFERRED for:", options:["All situations","Visibly soiled hands and after caring for patients with C. difficile or norovirus","Before invasive procedures","After removing gloves always"], answer:1, explanation:"Soap and water preferred: visibly soiled hands, after Clostridioides difficile (alcohol-resistant spores), norovirus (alcohol less effective), before eating. Alcohol rub: faster, more effective for non-soiled hands in most other situations." },
    { id:"p7q62", question:"What is the minimum safe distance from a water source that a toilet/latrine should be placed?", options:["5 meters","10 meters","30 meters (or ≥15 meters in some guidelines — varies by soil type)","100 meters"], answer:2, explanation:"WHO guidelines: latrines/pit toilets should be ≥30 meters from water sources (well, stream) and at a lower elevation to prevent groundwater contamination with fecal coliforms. Distance requirements vary by soil permeability." },
    { id:"p7q63", question:"Case fatality rate (CFR) measures:", options:["Deaths per 1,000 population","Proportion of confirmed disease cases that die: deaths / confirmed cases × 100%","Deaths per 100,000 population","Mortality from all causes"], answer:1, explanation:"CFR = (deaths/confirmed cases) × 100%. Measures lethality of disease in DIAGNOSED cases. Differs from infection fatality rate (IFR) which includes undiagnosed cases. Ebola CFR: 25–90%; seasonal flu: <0.1%." },
    { id:"p7q64", question:"Which environmental factor is a major cause of lead poisoning in children?", options:["Drinking water only","Lead-based paint in pre-1978 housing (dust/chips), contaminated soil, imported toys, traditional remedies","Only industrial pollution","Food packaging only"], answer:1, explanation:"Sources of childhood lead exposure: lead paint dust/chips (primary), contaminated soil (near highways, former smelters), imported toys/jewelry, traditional remedies (kohl, surma, ayurvedic medicines), lead pipes in older homes." },
    { id:"p7q65", question:"Passive surveillance in public health means:", options:["Active case finding","Routine collection of health data by health facilities — reports submitted to health authorities by providers","Random sampling of population","Only laboratory reporting"], answer:1, explanation:"Passive surveillance: health providers routinely report cases of notifiable diseases to health authorities (standard reports). Active surveillance: health authorities actively seek out cases (call providers, review records, field investigations)." },
    { id:"p7q66", question:"Community-based rehabilitation (CBR) focuses on:", options:["Only hospital-based care","Rehabilitation, equal opportunities, and social inclusion of people with disabilities within communities, using local resources","Mental health only","Children under 5 only"], answer:1, explanation:"CBR: community-led approach using available community resources to rehabilitate disabled persons in their own environment — promotes social participation, education, livelihood, and empowerment. Less resource-intensive than institutional care." },
    { id:"p7q67", question:"Measles (rubeola) spreads by:", options:["Direct contact with lesions","Fecal-oral route","Airborne droplets — most contagious human pathogen (R0=12–18)","Mosquito vector"], answer:2, explanation:"Measles: airborne transmission (droplet nuclei survive up to 2 hours in air). Most contagious human pathogen. 1 case infects 12–18 susceptible contacts. 95% vaccination coverage needed for herd immunity." },
    { id:"p7q68", question:"A healthy lifestyle that prevents non-communicable diseases includes:", options:["Moderate exercise only","Regular physical activity (150 min/week moderate or 75 min vigorous), balanced diet, no tobacco, limited alcohol, stress management","High-intensity exercise daily only","Vitamin supplementation only"], answer:1, explanation:"WHO NCD prevention: ≥150 min moderate aerobic activity/week, healthy diet (limit salt/sugar/saturated fat, eat fruits/vegetables), no tobacco, alcohol ≤2 standard drinks/day, maintain healthy weight." },
    { id:"p7q69", question:"Sentinel surveillance collects data from:", options:["All health facilities nationwide","Selected strategically chosen sites (sentinel sites) to obtain timely representative data on specific conditions","Only private hospitals","Community health workers exclusively"], answer:1, explanation:"Sentinel surveillance: selected sites provide systematic, continuous data on specific conditions (influenza-like illness, HIV, TB drug resistance). More focused, higher quality, less costly than universal surveillance." },
    { id:"p7q70", question:"The purpose of an epidemiological case definition is:", options:["To diagnose individual patients clinically","To uniformly define 'cases' for surveillance and outbreak investigation purposes — not clinical diagnosis","To allocate treatment resources","To determine patient prognosis"], answer:1, explanation:"Case definition: standardized criteria (clinical, laboratory, epidemiological) to classify who is a 'case' for surveillance or outbreak purposes. Enables valid comparison across time and place. NOT the same as clinical diagnostic criteria." },
    { id:"p7q71", question:"A nurse is developing a health education program. The Bloom's taxonomy levels from lowest to highest are:", options:["Knowledge, Comprehension, Application, Analysis, Synthesis, Evaluation","Evaluation, Synthesis, Analysis, Application, Comprehension, Knowledge","Remember, Understand, Apply, Analyze, Evaluate, Create (revised Bloom's)","All are equally important"], answer:2, explanation:"Revised Bloom's taxonomy (Anderson & Krathwohl, 2001): Remember, Understand, Apply, Analyze, Evaluate, Create. Original (1956): Knowledge, Comprehension, Application, Analysis, Synthesis, Evaluation. Critical thinking (higher levels) is the goal." },
    { id:"p7q72", question:"The Expanded Programme on Immunization (EPI) in UAE/Gulf follows which schedule?", options:["Only 3 vaccines at birth","WHO recommended schedule + additional vaccines based on regional epidemiology (e.g., meningococcal, typhoid, varicella)","Only adult vaccines","No vaccination is mandatory"], answer:1, explanation:"UAE follows WHO EPI schedule with additional vaccines based on regional need and travel considerations. UAE-specific additions: meningococcal vaccine (pilgrims), varicella, hepatitis A, typhoid. Schedule available on UAE Ministry of Health website." },
    { id:"p7q73", question:"Non-governmental organizations (NGOs) in health contribute by:", options:["Replacing government health services","Complementing government services — reaching underserved populations, innovating, advocating, and funding health programs","Only fundraising","Only emergency disaster relief"], answer:1, explanation:"NGOs in health: provide services in underserved areas (remote, conflict zones), innovate new approaches, advocate for policy change, complement government programs, fund research, provide humanitarian aid. WHO closely partners with NGOs." },
    { id:"p7q74", question:"The concept of 'one health' recognizes:", options:["That only human health matters","Interconnection between human health, animal health, and environmental health — most human infections originate in animals (zoonoses)","That environmental health supersedes human health","Animal and human health are completely separate"], answer:1, explanation:"One Health: collaborative, multisectoral approach recognizing that human, animal, and environmental health are interconnected. ~60% of human infectious diseases are zoonotic origin. Requires veterinary, medical, environmental, and policy collaboration." },
    { id:"p7q75", question:"Which mode of HIV transmission carries the HIGHEST risk per exposure?", options:["Oral sex","Needle sharing among IV drug users","Receptive anal intercourse (~1.4% per act)","Breastfeeding"], answer:2, explanation:"HIV transmission risk per act: receptive anal intercourse (~1.4%), needle sharing (~0.63%), receptive vaginal (~0.08%), insertive anal (~0.11%), breastfeeding (~0.01–0.15% per month). All risks can be reduced substantially." },
    { id:"p7q76", question:"WHO defines a healthy diet as:", options:["High protein, low carbohydrate","Rich in fruits, vegetables, legumes, whole grains, nuts; low in free sugars (<10% energy), salt (<5g/day), saturated and trans fats","No specific recommendations","High in dairy products"], answer:1, explanation:"WHO healthy diet: ≥400g fruit/vegetables/day (5 portions), limit free sugars (<10% total energy, ideally <5%), limit saturated fat (<10% energy), eliminate trans fat (<1%), limit salt <5g/day, adequate fiber (≥25g/day)." },
    { id:"p7q77", question:"Trachoma, the leading infectious cause of blindness, is prevented by:", options:["Vaccination","SAFE strategy: Surgery (trichiasis), Antibiotics (azithromycin), Facial cleanliness, Environmental improvement","Antiviral drugs","Eye drops alone"], answer:1, explanation:"Trachoma (Chlamydia trachomatis): repeated infections cause scarring → trichiasis (eyelashes scratch cornea) → corneal opacity → blindness. SAFE strategy: Surgery (correct trichiasis), Antibiotics (azithromycin mass treatment), Facial cleanliness, Environmental improvement." },
    { id:"p7q78", question:"The goal of Healthy Cities initiative is:", options:["Building new hospitals","Creating urban environments that support health — addressing urban social determinants and governance for health","Only reducing air pollution","Improving emergency services"], answer:1, explanation:"WHO Healthy Cities: places health high on political agenda of cities, builds local leadership, creates supportive environments. Addresses urban health inequities, social determinants, and governance for public health." },
    { id:"p7q79", question:"Which public health intervention has saved the most lives in history?", options:["Modern surgery","Antibiotics","Vaccination — estimated to prevent 2–3 million deaths/year","Chemotherapy"], answer:2, explanation:"Vaccination is widely considered the most impactful public health intervention after clean water and sanitation. WHO estimates vaccination prevents 2–3 million deaths annually. Smallpox eradication alone is the greatest public health achievement." },
    { id:"p7q80", question:"Surveillance for healthcare-associated infections (HAI) requires monitoring:", options:["Only surgical site infections","CAUTI, CLABSI, surgical site infections (SSI), CLAD, VAP, and Clostridioides difficile — using standardized definitions","Only blood stream infections","Antibiotic use only"], answer:1, explanation:"HAI surveillance targets (CDC/NHSN): CAUTI (catheter-associated UTI), CLABSI (central line bloodstream infection), SSI (surgical site), VAP/VAE (ventilator-associated), C. difficile, MRSA. Evidence-based bundles reduce each type." },
    { id:"p7q81", question:"Fluoridation of water is a public health measure that prevents:", options:["Gastrointestinal disease","Dental caries (tooth decay) — community water fluoridation at 0.7–1.2 ppm","Cardiovascular disease","Mental health disorders"], answer:1, explanation:"Community water fluoridation (0.7 mg/L recommended in US) reduces dental caries by 25–35%. One of the greatest public health achievements of the 20th century. Excess fluoride (>4 mg/L) causes dental/skeletal fluorosis." },
    { id:"p7q82", question:"The 'iceberg' concept in epidemiology describes:", options:["Climate change effects on disease","How the visible cases (clinical disease) represent only a fraction of the total infected population (subclinical cases below)","Frozen water contamination risks","Arctic disease patterns"], answer:1, explanation:"Iceberg concept: for every diagnosed clinical case, many more cases exist below the surface (subclinical, mild, undiagnosed). Polio tip: 1 paralytic case → 200 infected. Surveillance underestimates true disease burden." },
    { id:"p7q83", question:"The Global Burden of Disease (GBD) study provides:", options:["Individual patient data","Comprehensive epidemiological data on mortality, morbidity, and risk factors across countries, diseases, and time","Clinical trial results","Drug efficacy data"], answer:1, explanation:"GBD: systematic study of health trends in 195 countries for 300+ diseases and injuries and 70+ risk factors. Provides DALYs, YLLs, YLDs, mortality data. Published in The Lancet. Used for health priority setting." },
    { id:"p7q84", question:"Pre-exposure prophylaxis (PrEP) for HIV refers to:", options:["Post-exposure antiretrovirals","HIV-negative individuals taking antiretrovirals (tenofovir/emtricitabine) daily to prevent HIV infection","HIV vaccine","Partner notification only"], answer:1, explanation:"PrEP: oral TDF/FTC (Truvada) or TDF/3TC daily in HIV-negative people at high risk. When taken correctly, reduces HIV risk by >99%. Also: injectable cabotegravir (every 2 months). WHO recommends PrEP as key prevention tool." },
    { id:"p7q85", question:"Which behavioral risk factor contributes to the MOST deaths globally?", options:["Physical inactivity","Unhealthy diet","Tobacco use (kills ~8 million/year)","Alcohol use"], answer:2, explanation:"Tobacco: ~8 million deaths/year (7 million direct, 1.2 million passive smoking). Major cause of CVD, cancer (lung, oral, bladder), COPD, stroke. Most preventable cause of death globally." },
    { id:"p7q86", question:"Polio eradication strategy includes:", options:["Only routine immunization","Routine immunization + supplementary immunization activities (mass campaigns) + acute flaccid paralysis surveillance + outbreak response","Herd immunity alone","Quarantine of all travelers"], answer:1, explanation:"Global Polio Eradication Initiative (GPEI): routine immunization to maintain coverage, supplementary immunization activities (NIDs — National Immunization Days), AFP surveillance (detect cases), rapid outbreak response immunization." },
    { id:"p7q87", question:"Wasting (acute malnutrition) in children is defined as:", options:["Height-for-age Z score <-2 (stunting)","Weight-for-height Z score <-2 (MUAC <12.5 cm for severe)","BMI >25","Weight-for-age Z score <-2 (underweight)"], answer:1, explanation:"Malnutrition definitions: Wasting = weight-for-height Z score <-2 (recent/acute); Stunting = height-for-age Z score <-2 (chronic); Underweight = weight-for-age Z score <-2. MUAC <12.5 cm = severe acute malnutrition." },
    { id:"p7q88", question:"DOTS-Plus (for MDR-TB) means:", options:["Extended TB treatment for drug-sensitive TB","Treatment of multidrug-resistant TB (resistant to isoniazid + rifampicin) using second-line drugs under observation","Faster TB treatment","Preventive TB therapy"], answer:1, explanation:"MDR-TB: resistant to INH and rifampicin (two most effective first-line drugs). Requires 18–24 months of second-line drugs (fluoroquinolones, injectable aminoglycosides, bedaquiline, linezolid). Extremely expensive and toxic." },
    { id:"p7q89", question:"The demographic transition theory describes:", options:["Migration patterns","Shift from high birth/death rates to low birth/death rates as countries develop economically","Population aging only","Urbanization effects on health"], answer:1, explanation:"Demographic transition: Stage 1 (high birth + high death rates), Stage 2 (death rate falls, birth rate high → population explosion), Stage 3 (birth rate falls), Stage 4 (low birth + low death). Most developed countries in Stage 4." },
    { id:"p7q90", question:"Which type of study is best for studying rare diseases?", options:["Randomized controlled trial","Cohort study","Case-control study (compares cases with disease to controls without)","Cross-sectional study"], answer:2, explanation:"Case-control study: compares people WITH disease (cases) to similar people WITHOUT disease (controls) for past exposures. Efficient for rare diseases and diseases with long latency. Produces odds ratios." },
    { id:"p7q91", question:"Herd immunity threshold for measles (requiring ~95% vaccination coverage) is because R0 is:", options:["2–4","5–7","12–18 (one of the highest of all infectious diseases)","1–2"], answer:2, explanation:"Measles R0 = 12–18 (most infectious human pathogen). Herd immunity threshold = 1 - (1/R0) = 92–95%. If coverage falls below 95%, outbreaks occur. Recent outbreaks in Europe/US linked to vaccine hesitancy." },
    { id:"p7q92", question:"The 'epidemiological transition' refers to:", options:["Change in reporting systems","Shift from infectious diseases as leading cause of death to non-communicable diseases as countries develop","Change in doctor-to-patient ratios","Transition from rural to urban health systems"], answer:1, explanation:"Epidemiological transition (Omran, 1971): as countries develop, leading causes of death shift from infectious diseases (maternal, child, nutritional) to NCDs (cardiovascular disease, cancer, diabetes) — occurring globally." },
    { id:"p7q93", question:"School health programs primarily aim to:", options:["Replace parents in health education","Promote health of students and staff, provide health education, identify and manage health problems, create healthy school environments","Only provide vaccinations in schools","Mental health support only"], answer:1, explanation:"School health program components: health education curriculum, health services (screening, first aid, immunization), healthy school environment (safe facilities, nutrition), staff health, community engagement — using schools as health promotion platforms." },
    { id:"p7q94", question:"WASH (Water, Sanitation, and Hygiene) programs primarily target:", options:["Hospital infection control only","Prevention of diarrheal diseases, cholera, typhoid, trachoma, helminth infections through clean water, adequate sanitation, and handwashing promotion","HIV/AIDS prevention","Vaccination campaigns"], answer:1, explanation:"WASH: inadequate WASH causes 800,000+ deaths/year (mainly children under 5 from diarrhea). Safe water, improved sanitation (latrines), and handwashing with soap at critical times can reduce diarrhea by 25–40%." },
    { id:"p7q95", question:"A gold standard study design for evaluating health interventions is:", options:["Cross-sectional survey","Randomized controlled trial (RCT) — highest level of evidence for intervention effectiveness","Case report","Ecological study"], answer:1, explanation:"Evidence hierarchy: Meta-analysis/systematic review > RCT > Cohort > Case-control > Cross-sectional > Case report. RCT: random assignment to intervention/control eliminates selection bias. Gold standard for testing interventions." },
    { id:"p7q96", question:"Epidemiology is defined as:", options:["Study of individual patient diseases","Study of the distribution (who, when, where) and determinants (why, how) of health and disease in populations — to apply findings to control health problems","Study of microbiology","Study of clinical treatment outcomes"], answer:1, explanation:"Epidemiology: population science. Person (who gets sick), Place (where does disease occur), Time (when — trends, seasonality) — the 3 Ps of descriptive epidemiology. Analytic epidemiology identifies causes. Applied to disease prevention and control." },
    { id:"p7q97", question:"Which immunization route is used for oral polio vaccine (OPV)?", options:["Intramuscular","Intradermal","Oral (2 drops on tongue)","Subcutaneous"], answer:2, explanation:"OPV: 2 drops orally. Provides intestinal immunity (mucosal IgA), excellent for eradication. Rare complication: vaccine-associated paralytic polio (VAPP, ~1 per 2.4 million doses). IPV (inactivated) given IM — safer but no intestinal immunity." },
    { id:"p7q98", question:"The concept of 'upstream' health interventions focuses on:", options:["Clinical treatment at the bedside","Addressing root causes and social determinants of health — poverty, inequality, education, housing (not just treating downstream consequences)","Hospital management","Individual behavior change only"], answer:1, explanation:"Upstream (Geoffrey Rose): addressing structural/social determinants of health (poverty, inequality, environment) to prevent disease in populations — more population impact than downstream clinical interventions on individual patients." },
    { id:"p7q99", question:"The 'natural history of disease' includes:", options:["Medical treatment phases only","Stages: Susceptibility → Subclinical disease (incubation) → Clinical disease → Recovery/disability/death — occurring without intervention","Only clinical phases","Post-treatment stages only"], answer:1, explanation:"Natural history (without intervention): Susceptibility (exposed, not yet infected) → Subclinical disease (asymptomatic, pathological changes begin) → Clinical disease (signs/symptoms) → Outcomes (recovery, disability, death). Prevention targets each stage." },
    { id:"p7q100", question:"The Healthy Worker Effect describes:", options:["Workers being more productive","Bias in occupational studies: employed workers are healthier than the general population (which includes sick people) — understates occupational risk","Workplace stress effects","Exercise benefits for workers"], answer:1, explanation:"Healthy Worker Effect: occupational cohort studies compare workers to general population. But sick people are less likely to be employed → workers appear healthier. This selection bias makes occupational hazards look less harmful than they are." }
  ]
};
export default phase7;
